// ===== Stealth.min.js 占位文件 =====
// 此文件需要替换为真正的 stealth.min.js 反检测脚本
// 下载地址: https://raw.githubusercontent.com/nicedayzhu/playwright_stealth/main/playwright_stealth/js/stealth.min.js
// 或使用 playwright-extra / puppeteer-extra-plugin-stealth 的版本
//
// 该脚本的作用是隐藏 Playwright/Puppeteer 的自动化特征，
// 使得网站无法通过 navigator.webdriver 等属性检测到爬虫
//
// 临时替代方案（基本的反检测）:

Object.defineProperty(navigator, 'webdriver', {
    get: () => undefined
});

// 覆盖 chrome 对象
window.chrome = {
    runtime: {}
};

// 覆盖 permissions 查询
const originalQuery = window.navigator.permissions.query;
window.navigator.permissions.query = (parameters) => (
    parameters.name === 'notifications' ?
    Promise.resolve({ state: Notification.permission }) :
    originalQuery(parameters)
);

// 覆盖 plugins 长度
Object.defineProperty(navigator, 'plugins', {
    get: () => [1, 2, 3, 4, 5]
});

// 覆盖 languages
Object.defineProperty(navigator, 'languages', {
    get: () => ['zh-CN', 'zh', 'en']
});

console.log('stealth.min.js loaded (basic version)');
